import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { supabaseUrl, supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import {
    Shield,
    AlertTriangle,
    CheckCircle,
    MapPin,
    Search,
    AlertOctagon,
    Loader2
} from 'lucide-react';
import { motion } from 'framer-motion';

interface Violation {
    id?: string;
    keyword_id?: string;
    text?: string;
    match_type?: string;
    city?: string;
    region?: string;
    clicks?: number;
    cost?: number;
    issue: string;
    severity: 'high' | 'medium';
}

interface AuditResult {
    brand_violations: Violation[];
    geo_violations: Violation[];
    brand_health_score: number;
}

const item = {
    hidden: { y: 20, opacity: 0 },
    show: { y: 0, opacity: 1 }
};

export default function GoogleAdsAudit() {
    const { session } = useAuth();

    // We fetch user's company_id first
    const { data: userData } = useQuery({
        queryKey: ['user-company'],
        queryFn: async () => {
            const { data } = await supabase.auth.getUser();
            if (!data.user) return null;
            const { data: profile } = await supabase.from('users').select('company_id').eq('id', data.user.id).single();
            return profile?.company_id;
        }
    });

    const { data: auditData, isLoading, refetch } = useQuery({
        queryKey: ['google-audit-data', userData],
        enabled: !!userData && !!session?.access_token,
        queryFn: async () => {
            const response = await fetch(`${supabaseUrl}/functions/v1/google-audit`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${session?.access_token}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ company_id: userData }),
            });
            if (!response.ok) throw new Error('Falha na auditoria');
            return response.json() as Promise<AuditResult>;
        }
    });

    if (isLoading) return <div className="p-20 flex justify-center"><Loader2 className="w-8 h-8 animate-spin text-ch-orange" /></div>;

    const score = auditData?.brand_health_score || 0;
    const isHealthy = score > 80;

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <motion.div variants={item} className="md:col-span-1 glass-premium rounded-[2.5rem] p-8 relative overflow-hidden flex flex-col items-center justify-center text-center border-white/10">
                    <div className={`w-32 h-32 rounded-full border-4 flex items-center justify-center mb-4 ${isHealthy ? 'border-emerald-500 text-emerald-500' : 'border-rose-500 text-rose-500'}`}>
                        <span className="text-5xl font-black tracking-tighter">{score}</span>
                    </div>
                    <h3 className="text-lg font-black text-ch-white uppercase tracking-tight">Brand Health Score</h3>
                    <p className="text-[10px] text-ch-text-muted mt-2 font-medium">Índice de conformidade da marca</p>

                    <div className="absolute top-0 right-0 p-10 opacity-5 pointer-events-none">
                        <Shield className="w-40 h-40" />
                    </div>
                </motion.div>

                <div className="md:col-span-2 grid grid-cols-1 gap-4">
                    {/* Summary Cards */}
                    <Card className="bg-white/[0.02] border-white/5">
                        <CardHeader className="pb-2">
                            <CardTitle className="text-[10px] font-black uppercase text-ch-text-dimmed flex items-center gap-2">
                                <Search className="w-4 h-4 text-ch-orange" /> Proteção de Keywords
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="flex items-center justify-between">
                                <div>
                                    <span className="text-2xl font-black text-ch-white">{auditData?.brand_violations.length}</span>
                                    <span className="text-xs font-bold text-ch-text-muted ml-2">Infrações Detectadas</span>
                                </div>
                                <Button variant="outline" size="sm" className="h-8 text-[9px] uppercase font-black tracking-widest bg-transparent border-white/10 hover:bg-white/5">Verificar</Button>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="bg-white/[0.02] border-white/5">
                        <CardHeader className="pb-2">
                            <CardTitle className="text-[10px] font-black uppercase text-ch-text-dimmed flex items-center gap-2">
                                <MapPin className="w-4 h-4 text-blue-400" /> Geo-Compliance
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="flex items-center justify-between">
                                <div>
                                    <span className="text-2xl font-black text-ch-white">{auditData?.geo_violations.length}</span>
                                    <span className="text-xs font-bold text-ch-text-muted ml-2">Praças Irregulares</span>
                                </div>
                                <Button variant="outline" size="sm" className="h-8 text-[9px] uppercase font-black tracking-widest bg-transparent border-white/10 hover:bg-white/5">Detalhes</Button>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>

            {/* Violation Lists */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <motion.div variants={item} className="glass-card rounded-3xl p-6 border-white/5 space-y-4">
                    <div className="flex items-center gap-2 mb-4">
                        <AlertOctagon className="w-5 h-5 text-rose-500" />
                        <h3 className="text-sm font-black text-ch-white uppercase tracking-tight">Infrações de Marca (High Risk)</h3>
                    </div>

                    <div className="space-y-3">
                        {auditData?.brand_violations.length === 0 ? (
                            <div className="p-8 text-center bg-white/[0.02] rounded-2xl border border-white/5 border-dashed">
                                <CheckCircle className="w-8 h-8 text-emerald-500 mx-auto mb-3 opacity-50" />
                                <p className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest">Nenhuma infração detectada</p>
                            </div>
                        ) : (
                            auditData?.brand_violations.map((v, i) => (
                                <div key={i} className="p-4 bg-rose-500/10 border border-rose-500/20 rounded-xl space-y-2">
                                    <div className="flex justify-between items-start">
                                        <span className="text-xs font-black text-rose-400 uppercase">"{v.text}"</span>
                                        <span className="px-2 py-0.5 rounded bg-rose-500/20 text-[9px] font-black text-rose-400 uppercase tracking-wider">{v.match_type}</span>
                                    </div>
                                    <p className="text-[10px] font-medium text-rose-300/80">{v.issue}</p>
                                </div>
                            ))
                        )}
                    </div>
                </motion.div>

                <motion.div variants={item} className="glass-card rounded-3xl p-6 border-white/5 space-y-4">
                    <div className="flex items-center gap-2 mb-4">
                        <MapPin className="w-5 h-5 text-amber-500" />
                        <h3 className="text-sm font-black text-ch-white uppercase tracking-tight">Infrações Geográficas (Free BID)</h3>
                    </div>

                    <div className="space-y-3">
                        {auditData?.geo_violations.length === 0 ? (
                            <div className="p-8 text-center bg-white/[0.02] rounded-2xl border border-white/5 border-dashed">
                                <CheckCircle className="w-8 h-8 text-emerald-500 mx-auto mb-3 opacity-50" />
                                <p className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest">Geo-Targeting Validado</p>
                            </div>
                        ) : (
                            auditData?.geo_violations.map((v, i) => (
                                <div key={i} className="p-4 bg-amber-500/10 border border-amber-500/20 rounded-xl space-y-2">
                                    <div className="flex justify-between items-start">
                                        <div className="flex items-center gap-2">
                                            <MapPin className="w-3 h-3 text-amber-500" />
                                            <span className="text-xs font-black text-amber-500 uppercase">{v.city || v.region}</span>
                                        </div>
                                        <span className="px-2 py-0.5 rounded bg-amber-500/20 text-[9px] font-black text-amber-500 uppercase tracking-wider">{v.clicks} Clicks</span>
                                    </div>
                                    <p className="text-[10px] font-medium text-amber-300/80">{v.issue}</p>
                                </div>
                            ))
                        )}
                    </div>
                </motion.div>
            </div>
        </div>
    );
}

import { motion } from 'framer-motion';
import { useGoogleAds } from '@/hooks/useGoogleAds';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import {
    MapPin,
    TrendingUp,
    DollarSign,
    Globe,
    ArrowUpRight,
    ArrowDownRight,
    Download,
    AlertCircle
} from 'lucide-react';
import {
    BarChart,
    Bar,
    XAxis,
    YAxis,
    Tooltip,
    ResponsiveContainer,
    CartesianGrid,
    Cell,
    PieChart,
    Pie,
    Legend
} from 'recharts';

const item = {
    hidden: { y: 20, opacity: 0 },
    show: { y: 0, opacity: 1 }
};

export default function GoogleAdsGeo() {
    const { geoPerformance, isLoading } = useGoogleAds();

    if (isLoading) {
        return (
            <div className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <Skeleton className="h-32 rounded-xl bg-white/5" />
                    <Skeleton className="h-32 rounded-xl bg-white/5" />
                    <Skeleton className="h-32 rounded-xl bg-white/5" />
                </div>
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    <Skeleton className="h-[300px] rounded-3xl bg-white/5" />
                    <Skeleton className="h-[300px] rounded-3xl bg-white/5" />
                </div>
            </div>
        );
    }

    if (!geoPerformance?.length) {
        return (
            <div className="flex flex-col items-center justify-center p-12 text-center space-y-4 glass-card rounded-3xl border-white/5">
                <div className="p-4 bg-white/5 rounded-full">
                    <AlertCircle className="w-8 h-8 text-ch-text-dimmed" />
                </div>
                <div>
                    <h3 className="text-lg font-black text-ch-white uppercase">Aguardando Dados Geográficos</h3>
                    <p className="text-sm text-ch-text-muted">Os dados estão sendo processados.</p>
                </div>
            </div>
        );
    }

    // Sort by clicks to get top performers
    const sortedGeo = [...(geoPerformance || [])].sort((a, b) => b.clicks - a.clicks);

    // Process data for charts
    const topCities = sortedGeo.slice(0, 10).map(geo => ({
        name: geo.city_name || geo.region_name,
        clicks: geo.clicks,
        cost: geo.cost_micros / 1000000,
        cpc: (geo.cost_micros / 1000000) / (geo.clicks || 1)
    }));

    const regionDataObj = sortedGeo.reduce((acc, curr) => {
        const region = curr.region_name || 'Desconhecido';
        if (!acc[region]) acc[region] = 0;
        acc[region] += curr.clicks;
        return acc;
    }, {} as Record<string, number>);

    const pieData = Object.entries(regionDataObj).map(([name, value]) => ({ name, value }));
    const COLORS = ['#F97316', '#10B981', '#3B82F6', '#8B5CF6', '#EC4899', '#F59E0B'];

    // Stats
    const totalCities = sortedGeo.length;
    const topCityName = topCities[0]?.name || '-';
    // Format large numbers with 'k'
    const formatNumber = (num: number) => {
        if (num >= 1000) return `${(num / 1000).toFixed(1)} k`;
        return num.toString();
    };
    const topCityClicks = formatNumber(topCities[0]?.clicks || 0);

    // Calculate best CPC (lowest > 0)
    const bestCpcGeo = sortedGeo.filter(g => g.clicks > 0).sort((a, b) => (a.cost_micros / a.clicks) - (b.cost_micros / b.clicks))[0];
    const bestCpcValue = bestCpcGeo ? ((bestCpcGeo.cost_micros / 1000000) / bestCpcGeo.clicks).toFixed(2) : '0.00';
    const bestCpcCity = bestCpcGeo?.city_name || '-';

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <Card className="bg-white/[0.02] border-white/5">
                    <CardHeader className="flex flex-row items-center justify-between pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted">Top Cidade (Volume)</CardTitle>
                        <MapPin className="w-4 h-4 text-ch-orange" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-black text-ch-white">{topCityName}</div>
                        <p className="text-[10px] text-ch-orange font-bold mt-1 flex items-center">
                            <ArrowUpRight className="w-3 h-3 mr-1" />
                            {topCityClicks} cliques
                        </p>
                    </CardContent>
                </Card>
                <Card className="bg-white/[0.02] border-white/5">
                    <CardHeader className="flex flex-row items-center justify-between pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted">Melhor Eficiência (CPC)</CardTitle>
                        <DollarSign className="w-4 h-4 text-emerald-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-black text-ch-white">R$ {bestCpcValue}</div>
                        <p className="text-[10px] text-emerald-500 font-bold mt-1 flex items-center">
                            <ArrowDownRight className="w-3 h-3 mr-1" />
                            {bestCpcCity}
                        </p>
                    </CardContent>
                </Card>
                <Card className="bg-white/[0.02] border-white/5">
                    <CardHeader className="flex flex-row items-center justify-between pb-2">
                        <CardTitle className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted">Cobertura Geográfica</CardTitle>
                        <Globe className="w-4 h-4 text-blue-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-black text-ch-white">{totalCities}</div>
                        <p className="text-[10px] text-blue-500 font-bold mt-1">Cidades/Regiões Ativas</p>
                    </CardContent>
                </Card>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <motion.div variants={item} className="glass-card rounded-3xl p-6 border-white/5">
                    <h3 className="text-sm font-black text-ch-white uppercase tracking-tight mb-6 flex items-center gap-2">
                        <TrendingUp className="w-4 h-4 text-emerald-500" />
                        Top 10 Cidades por Cliques
                    </h3>
                    <div className="h-[300px] w-full">
                        {topCities.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={topCities} layout="vertical" margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#ffffff10" horizontal={false} />
                                    <XAxis type="number" stroke="#ffffff40" fontSize={10} tickLine={false} axisLine={false} />
                                    <YAxis dataKey="name" type="category" stroke="#ffffff" fontSize={10} tickLine={false} axisLine={false} width={100} />
                                    <Tooltip
                                        contentStyle={{ backgroundColor: '#111', borderColor: '#333', borderRadius: '8px' }}
                                        itemStyle={{ fontSize: '11px', fontWeight: 'bold' }}
                                        cursor={{ fill: 'transparent' }}
                                    />
                                    <Bar dataKey="clicks" name="Cliques" radius={[0, 4, 4, 0]} barSize={20} fill="#F97316" />
                                </BarChart>
                            </ResponsiveContainer>
                        ) : (
                            <div className="h-full flex items-center justify-center text-ch-text-dimmed text-xs">Sem dados suficientes</div>
                        )}
                    </div>
                </motion.div>

                <motion.div variants={item} className="glass-card rounded-3xl p-6 border-white/5">
                    <h3 className="text-sm font-black text-ch-white uppercase tracking-tight mb-6 flex items-center gap-2">
                        <Globe className="w-4 h-4 text-blue-500" />
                        Distribuição por Região
                    </h3>
                    <div className="h-[300px] w-full flex items-center justify-center">
                        {pieData.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie
                                        data={pieData}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={60}
                                        outerRadius={80}
                                        fill="#8884d8"
                                        paddingAngle={5}
                                        dataKey="value"
                                    >
                                        {pieData.map((entry, index) => (
                                            <Cell key={`cell - ${index} `} fill={COLORS[index % COLORS.length]} />
                                        ))}
                                    </Pie>
                                    <Tooltip
                                        contentStyle={{ backgroundColor: '#111', borderColor: '#333', borderRadius: '8px' }}
                                        itemStyle={{ fontSize: '12px', fontWeight: 'bold', color: '#fff' }}
                                    />
                                    <Legend
                                        layout="vertical"
                                        verticalAlign="middle"
                                        align="right"
                                        iconSize={8}
                                        wrapperStyle={{ fontSize: '10px', color: '#999' }}
                                    />
                                </PieChart>
                            </ResponsiveContainer>
                        ) : (
                            <div className="h-full flex items-center justify-center text-ch-text-dimmed text-xs">Sem dados suficientes</div>
                        )}
                    </div>
                </motion.div>
            </div>

            <motion.div variants={item} className="glass-card rounded-3xl p-6 border-white/5 space-y-4">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <MapPin className="w-5 h-5 text-ch-orange" />
                        <div>
                            <h3 className="text-sm font-black text-ch-white uppercase tracking-tight">Detalhamento por Unidade</h3>
                            <p className="text-[10px] text-ch-text-dimmed font-medium">Dados brutos de performance</p>
                        </div>
                    </div>
                    <Button variant="outline" size="sm" className="h-8 text-[10px] uppercase font-bold tracking-widest border-white/10 hover:bg-white/5 gap-2">
                        <Download className="w-3 h-3" />
                        Exportar CSV
                    </Button>
                </div>


                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="border-b border-white/10 text-[10px] font-black text-ch-text-dimmed uppercase tracking-widest">
                                <th className="py-3 px-4">Localidade</th>
                                <th className="py-3 px-4 text-right">Cliques</th>
                                <th className="py-3 px-4 text-right">Impressões</th>
                                <th className="py-3 px-4 text-right">Custo</th>
                                <th className="py-3 px-4 text-right">CPC Médio</th>
                                <th className="py-3 px-4 text-right">Conv.</th>
                            </tr>
                        </thead>
                        <tbody className="text-xs font-medium text-ch-white/80">
                            {geoPerformance?.map((geo, i) => (
                                <tr key={i} className="border-b border-white/5 hover:bg-white/[0.02] transition-colors">
                                    <td className="py-3 px-4 font-bold text-white">{geo.city_name || geo.region_name} <span className="text-ch-text-dimmed font-normal text-[10px] ml-1">({geo.region_name})</span></td>
                                    <td className="py-3 px-4 text-right">{geo.clicks}</td>
                                    <td className="py-3 px-4 text-right">{geo.impressions}</td>
                                    <td className="py-3 px-4 text-right">R$ {(geo.cost_micros / 1000000).toFixed(2)}</td>
                                    <td className="py-3 px-4 text-right text-emerald-400">R$ {((geo.cost_micros / 1000000) / (geo.clicks || 1)).toFixed(2)}</td>
                                    <td className="py-3 px-4 text-right">{geo.conversions}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </motion.div>
        </div>
    );
}
